refsection.programlisting:

load(GROCERDIR+'/data/bdhenderic.dat');
bounds('1964q3','1989q2');
rols=ols('delts(lm1-lp)','delts(lp)','delts(lagts(1,lm1-lp-ly))','rnet', 'lagts(1,lm1-lp-ly)', 'const');
reliability(rols,[0.3 0.6 0.4 0.7],0.05)
// From Hendry and Ericsson estimation, calculates the reliability of the coefficients at a 5% level,
// using Hendry and Krolzig proposed parametrisation (w=[0.3 0.6 0.4 0.7]).
